import os
import requests

def main(event):
    deal_id = event["inputFields"]["hs_object_id"]
    custom_object_type = "2-7957429"  # replace with your custom object type ID

    url = f"https://api.hubapi.com/crm/v4/objects/deal/{deal_id}/associations/{custom_object_type}"

    # Authorization
    access_token = os.environ.get('photon_association_handler')

    # Headers
    headers = {
        "Authorization": f"Bearer {access_token}",
        "Content-Type": "application/json"
    }


    try:
        response = requests.get(url, headers=headers)
        response.raise_for_status()

        data = response.json()
        count = len(data.get("results", []))

        return {
            "outputFields": {
                "associated_object_count": count
            }
        }

    except Exception as e:
        print(f"Error fetching associations: {e}")
        return {
            "outputFields": {
                "associated_object_count": 0
            }
        }
